package com.google.gson.stream;
import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import com.google.gson.stream.JsonWriter;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.mockito.Mockito;

import java.io.IOException;
import java.io.StringWriter;
import java.io.Writer;
import java.lang.reflect.Field;
import java.lang.reflect.Method;

public class JsonWriterTest {

    private JsonWriter jsonWriter;
    private StringWriter stringWriter;

    @BeforeEach
    public void setUp() {
        stringWriter = new StringWriter();
        jsonWriter = new JsonWriter(stringWriter);
    }

    @Test
    public void testWriteDeferredName_withDeferredName() throws Exception {
        // Set deferredName field to a non-null value using reflection
        Field deferredNameField = JsonWriter.class.getDeclaredField("deferredName");
        deferredNameField.setAccessible(true);
        deferredNameField.set(jsonWriter, "testName");

        // Spy on jsonWriter to verify private methods called
        JsonWriter spyWriter = Mockito.spy(jsonWriter);

        // Because beforeName() and string(String) are private, spy them via reflection to verify invocation
        Method beforeNameMethod = JsonWriter.class.getDeclaredMethod("beforeName");
        beforeNameMethod.setAccessible(true);

        Method stringMethod = JsonWriter.class.getDeclaredMethod("string", String.class);
        stringMethod.setAccessible(true);

        // Invoke writeDeferredName via reflection
        Method writeDeferredNameMethod = JsonWriter.class.getDeclaredMethod("writeDeferredName");
        writeDeferredNameMethod.setAccessible(true);
        writeDeferredNameMethod.invoke(spyWriter);

        // Verify deferredName reset to null
        assertNull(deferredNameField.get(spyWriter));

        // Verify that beforeName() and string(String) were called once each
        // Since these are private, we cannot verify with Mockito directly.
        // Instead, we override them via spy and verify invocation count by spying on the spyWriter.

        // Unfortunately, Mockito cannot spy private methods directly.
        // So we can verify output written to underlying writer to indirectly confirm string() call.

        String output = stringWriter.toString();
        assertTrue(output.contains("testName") || output.length() > 0);

        // Also verify that no exception was thrown and deferredName is cleared
    }

    @Test
    public void testWriteDeferredName_withNullDeferredName() throws Exception {
        // Ensure deferredName is null
        Field deferredNameField = JsonWriter.class.getDeclaredField("deferredName");
        deferredNameField.setAccessible(true);
        deferredNameField.set(jsonWriter, null);

        // Invoke writeDeferredName via reflection
        Method writeDeferredNameMethod = JsonWriter.class.getDeclaredMethod("writeDeferredName");
        writeDeferredNameMethod.setAccessible(true);

        // Should do nothing and not throw
        writeDeferredNameMethod.invoke(jsonWriter);

        // deferredName remains null
        assertNull(deferredNameField.get(jsonWriter));

        // Output should be empty
        String output = stringWriter.toString();
        assertEquals("", output);
    }
}
